runs.final_dockerfile:
FROM php:8.4.19-fpm-alpine3.22 AS builder

WORKDIR /app

# Create a minimal autoloader so the library can be loaded without Composer at runtime
RUN mkdir -p vendor && cat > vendor/autoload.php <<'PHP'
<?php
spl_autoload_register(function ($class) {
  // PSR-4 autoloading mapping Cron\\ to src/ directory
  $file = __DIR__ . '/../src/' . str_replace('\\', '/', $class) . '.php';
  if (file_exists($file)) {
    require $file;
  }
});
PHP

# Copy source code into the image so autoloader can find classes
COPY src ./src
COPY tests ./tests

# Runtime stage will copy the built application
FROM php:8.4.19-fpm-alpine3.22 AS runtime

WORKDIR /app

# Copy built application (including vendor autoload)
COPY --from=builder /app /app

# Ensure PHP-FPM can run in the container
RUN mkdir -p /var/run/php

CMD ["php-fpm", "-F"]

